INSERT OR REPLACE INTO verses (id,work_id,division_id,ref,ordinal,devanagari,translit,uvaca,source_url) VALUES ('cb.adi.12.84','cb','cb.adi.12','ЧБ Ади 12.84',84,'এইমত আপন-ইচ্ছায় লীলা করি’ ।
স্বাভাবিক হৈলা প্রভু বায়ু পরিহরি’ ॥৮৪॥','эи-мата а̄пана иччха̄йа лӣла̄ кари
сва̄бха̄вика хаила̄ прабху ва̄йу парихари’',NULL,NULL),('cb.adi.12.85','cb','cb.adi.12','ЧБ Ади 12.85',85,'সর্ব্বগণে উঠিল আনন্দ-হরি-ধ্বনি ।
কেবা কারে বস্ত্র দেয়,—হেন নাহি জানি ॥৮৫॥','сарва-ган̣е ут̣хила а̄нанда-хари-дхвани
кеба̄ ка̄’ре вастра дейа, — хӣнана̄хи джа̄ни',NULL,NULL),('cb.adi.12.86','cb','cb.adi.12','ЧБ Ади 12.86',86,'সর্ব্বলোকে শুনি’ হইলা হরষিত ।
সবে বোলে,—“জীউ, জীউ এ-হেন পণ্ডিত” ॥৮৬॥','сарва-локе ш́уни’ хаила̄ хараш̣ита
сабе боле, — ‘джӣу, джӣу э-хӣнапан̣д̣ита’',NULL,NULL),('cb.adi.12.87','cb','cb.adi.12','ЧБ Ади 12.87',87,'এইমত রঙ্গ করে বৈকুণ্ঠের রায় ।
কে তানে জানিতে পারে, যদি না জানায় ? ॥৮৭॥','эи-мата ран̇га каре ваикун̣т̣хера ра̄йа
ке та̄’не джа̄ните па̄ре, йади на̄ джа̄на̄йа?',NULL,NULL),('cb.adi.12.88','cb','cb.adi.12','ЧБ Ади 12.88',88,'প্রভুরে দেখিয়া সর্ব্ব-বৈষ্ণবের গণ ।
সভে বোলে,—“ভজ, বাপ, কৃষ্ণের চরণ ॥৮৮॥','прабхуре декхийа̄ сарва-ваиш̣н̣авера ган̣а
сабхе боле, — ‘бхаджа, ба̄па, кр̣ш̣н̣ера чаран̣а',NULL,NULL),('cb.adi.12.89','cb','cb.adi.12','ЧБ Ади 12.89',89,'ক্ষণেকে নাহিক, বাপ, অনিত্য শরীর ।
তোমারে কি শিখাইমু, তুমি মহাধীর” ॥৮৯॥','кш̣ан̣еке на̄хика, ба̄па, анитйа ш́арӣра
тома̄ре ки ш́икха̄иму, туми маха̄дхӣра',NULL,NULL),('cb.adi.12.90','cb','cb.adi.12','ЧБ Ади 12.90',90,'হাসিয়া প্রভু সবারে করিয়া নমস্কার ।
পড়াইতে চলে শিষ্য-সংহতি অপার ॥৯০॥','ха̄сийа̄ прабху саба̄ре карийа̄ намаска̄ра
пад̣а̄ите чале ш́иш̣йа-сам̇хати апа̄ра',NULL,NULL),('cb.adi.12.91','cb','cb.adi.12','ЧБ Ади 12.91',91,'মুকুন্দ-সঞ্জয় পুণ্যবন্তের মন্দিরে ।
পড়ায়েন প্রভু চণ্ডীমণ্ডপ-ভিতরে ॥৯১॥','мукунда-сан̃джайа пун̣йавантера мандире
пад̣а̄йена прабху чан̣д̣ӣ-ман̣д̣апа-бхитаре',NULL,NULL),('cb.adi.12.92','cb','cb.adi.12','ЧБ Ади 12.92',92,'পরম-সুগন্ধি পাক-তৈল প্রভু-শিরে ।
কোন পুণ্যবন্ত দেয়, প্রভু ব্যাখ্যা করে ॥৯২॥','парама-сугандхи па̄ка-таила прабху-ш́ире
кона пун̣йаванта дейа, прабху вйа̄кхйа̄ каре',NULL,NULL),('cb.adi.12.93','cb','cb.adi.12','ЧБ Ади 12.93',93,'চতুর্দ্দিকে শোভে পুণ্যবন্ত শিষ্যগণ ।
মাঝে প্রভু ব্যাখ্যা করে জগৎজীবন ॥৯৩॥','чатур-дике ш́обхе пун̣йаванта ш́иш̣йа-ган̣а
ма̄джхе прабху вйа̄кхйа̄ каре джагат-джӣвана',NULL,NULL),('cb.adi.12.94','cb','cb.adi.12','ЧБ Ади 12.94',94,'সে-শোভার মহিমা ত’ কহিতে না পারি ।
উপমা দিবাঙ কিবা, না দেখি বিচারি’ ॥৯৪॥','се ш́обха̄ра махима̄ та’ кахите на̄ па̄ри
упама̄ диба̄н̇а киба̄, на̄ декхи вича̄ри’',NULL,NULL),('cb.adi.12.95','cb','cb.adi.12','ЧБ Ади 12.95',95,'হেন বুঝি যেন সনকাদি-শিষ্যগণে ।
নারায়ণে বেড়ি’ বৈসে বদরিকাশ্রমে ॥৯৫॥','хӣнабуджхи йена санака̄ди-ш́иш̣йа-ган̣е
на̄ра̄йан̣е вед̣и’ васе бадарика̄ш́раме',NULL,NULL),('cb.adi.12.96','cb','cb.adi.12','ЧБ Ади 12.96',96,'তাঁ’সবারে লৈয়া যেন প্রভু সে পড়ায় ।
হেন বুঝি সেই লীলা করে গৌর-রায় ॥৯৬॥','та̄н̇’ саба̄ре лаийа̄ йена прабху се пад̣а̄йа
хӣнабуджхи сеи лӣла̄ каре гаура-ра̄йа',NULL,NULL),('cb.adi.12.97','cb','cb.adi.12','ЧБ Ади 12.97',97,'সেই বদরিকাশ্রমবাসী নারায়ণ ।
নিশ্চয় জানিহ এই শচীর নন্দন ॥৯৭॥','сеи бадарика̄ш́рама-ва̄сӣ на̄ра̄йан̣а
ниш́чайа джа̄ниха эи ш́ачӣра нандана',NULL,NULL),('cb.adi.12.98','cb','cb.adi.12','ЧБ Ади 12.98',98,'অতএব শিষ্য-সঙ্গে সেই লীলা করে ।
বিদ্যারসে বৈকুণ্ঠের নায়ক বিহরে ॥৯৮॥','атаева ш́иш̣йа-сан̇ге сеи лӣла̄ каре
видйа̄-расе ваикун̣т̣хера на̄йака вихаре',NULL,NULL),('cb.adi.12.99','cb','cb.adi.12','ЧБ Ади 12.99',99,'পড়াইয়া প্রভু দুই-প্রহর হইলে ।
তবে শিষ্যগণ লৈয়া গঙ্গাস্নানে চলে ॥৯৯॥','пад̣а̄ийа̄ прабху дуи прахара хаиле
табе ш́иш̣йа-ган̣а лаийа̄ ган̇га̄-сна̄не чале',NULL,NULL),('cb.adi.12.100','cb','cb.adi.12','ЧБ Ади 12.100',100,'গঙ্গাজলে বিহার করিয়া কতক্ষণ ।
গৃহে আসি’ করে প্রভু শ্রীবিষ্ণু-পূজন ॥১০০॥','ган̇га̄-джале виха̄ра карийа̄ ката-кш̣ан̣а
гр̣хе а̄си’ каре прабху ш́рӣ-виш̣н̣у-пӯджана',NULL,NULL),('cb.adi.12.101','cb','cb.adi.12','ЧБ Ади 12.101',101,'তুলসীর জল দিয়া প্রদক্ষিণ করি’ ।
ভোজনে বসিলা গিয়া বলি’ ‘হরি হরি’ ॥১০১॥','туласӣра джала дийа̄ прадакш̣ин̣а кари’
бходжане васила̄ гийа̄ бали’ ‘хари-хари’',NULL,NULL),('cb.adi.12.102','cb','cb.adi.12','ЧБ Ади 12.102',102,'লক্ষ্মী দেন অন্ন, খা’ন বৈকুণ্ঠের পতি ।
নয়ন ভরিয়া দেখে আই পুণ্যবতী ॥১০২॥','лакш̣мӣ дена анна, кха̄’на ваикун̣т̣хера пати
найана бхарийа̄ декхе а̄и пун̣йаватӣ',NULL,NULL),('cb.adi.12.103','cb','cb.adi.12','ЧБ Ади 12.103',103,'ভোজন-অন্তরে করি’ তাম্বূল চর্ব্বণ ।
শয়ন করেন, লক্ষ্মী সেবেন চরণ ॥১০৩॥','бходжана-антаре кари’ та̄мбӯла чарван̣а
ш́айана карена, лакш̣мӣ севена чаран̣а',NULL,NULL),('cb.adi.12.104','cb','cb.adi.12','ЧБ Ади 12.104',104,'কতক্ষণ যোগনিদ্রা-প্রতি দৃষ্টি দিয়া ।
পুনঃ প্রভু চলিলেন পুস্তক লইয়া ॥১০৪॥','ката-кш̣ан̣а йога-нидра̄-прати др̣ш̣т̣и дийа̄
пунах̣ прабху чалилена пустака лаийа̄',NULL,NULL),('cb.adi.12.105','cb','cb.adi.12','ЧБ Ади 12.105',105,'নগরে আসিয়া করে বিবিধ বিলাস ।
সবার সহিত করে হাসিয়া সম্ভাষ ॥১০৫॥','нагаре а̄сийа̄ каре вивидха вила̄са
саба̄ра сахита каре ха̄сийа̄ самбха̄ш̣а',NULL,NULL),('cb.adi.12.106','cb','cb.adi.12','ЧБ Ади 12.106',106,'যদ্যপি প্রভুর কেহ তত্ত্ব নাহি জানে ।
তথাপি সাধ্বস করে দেখি’ সর্ব্বজনে ॥১০৬॥','йадйапи прабхура кеха таттва на̄хи джа̄не
татха̄пи са̄дхаваса каре декхи’ сарва-джане',NULL,NULL),('cb.adi.12.107','cb','cb.adi.12','ЧБ Ади 12.107',107,'নগরে ভ্রমণ করে শ্রীশচীনন্দন ।
দেবের দুর্ল্লভ বস্তু দেখে সর্ব্বজন ॥১০৭॥','нагаре бхраман̣а каре’ ш́рӣ-ш́ачӣнандана',NULL,NULL),('cb.adi.12.108','cb','cb.adi.12','ЧБ Ади 12.108',108,'উঠিলেন প্রভু তন্তুবায়ের দুয়ারে ।
দেখিয়া সম্ভ্রমে তন্তুবায় নমস্করে ॥১০৮॥','ут̣хилена прабху танту-ва̄йера дуйа̄ре
декхийа̄ самбхраме танту-ва̄йа намаска̄ре',NULL,NULL),('cb.adi.12.109','cb','cb.adi.12','ЧБ Ади 12.109',109,'“ভাল বস্ত্র আন”,—প্রভু বোলয়ে বচন ।
তন্তুবায় বস্ত্র আনিলেন সেইক্ষণ ॥১০৯॥','‘бха̄ла вастра а̄на’, — прабху болайе вачана
танту-ва̄йа вастра а̄нилена сеи-кш̣ан̣а',NULL,NULL),('cb.adi.12.110','cb','cb.adi.12','ЧБ Ади 12.110',110,'প্রভু বোলে,—“এ বস্ত্রের কি মূল্য লইবা ?” ।
তন্তুবায় বোলে,—“তুমি আপনে যে দিবা” ॥১১০॥','прабху боле, — ‘е вастрера ки мӯлйа лаи?’
танту-ва̄йа боле, — ‘туми а̄пане йе диба̄’',NULL,NULL),('cb.adi.12.111','cb','cb.adi.12','ЧБ Ади 12.111',111,'মূল্য করি’ বোলে প্রভু,—“এবে কড়ি নাই” ।
তাঁতি বোলে,—“দশে-পক্ষে দিও যে গোসাঞি ॥১১১॥','мӯлйа кари’ боле прабху, — ‘ебе кад̣и на̄и’
та̄н̇ти боле, — ‘даш́е пакш̣е дио йе госа̄н̃и',NULL,NULL),('cb.adi.12.112','cb','cb.adi.12','ЧБ Ади 12.112',112,'বস্ত্র লৈয়া পর’ তুমি পরম-সন্তোষে ।
পাছে তুমি কড়ি মোরে দিও সমাবেশে” ॥১১২॥','вастра лаийа̄ пара’ туми парама сантош̣е
па̄чхе туми кад̣и море дио сама̄веш́е’',NULL,NULL),('cb.adi.12.113','cb','cb.adi.12','ЧБ Ади 12.113',113,'তন্তুবায়-প্রতি প্রভু শুভ-দৃষ্টি করি’ ।
উঠিলেন গিয়া প্রভু গোয়ালার পুরী ॥১১৩॥','танту-ва̄йа-прати прабху ш́убха-др̣ш̣т̣и кари’
ут̣хилена гийа̄ прабху гойа̄ла̄ра пурӣ',NULL,NULL),('cb.adi.12.114','cb','cb.adi.12','ЧБ Ади 12.114',114,'বসিলেন মহাপ্রভু গোপের দুয়ারে ।
ব্রাহ্মণ-সম্বন্ধে প্রভু পরিহাস করে ॥১১৪॥','василена маха̄прабху гопӣра дуйа̄ре
бра̄хман̣а-самбандхе прабху париха̄са каре',NULL,NULL),('cb.adi.12.115','cb','cb.adi.12','ЧБ Ади 12.115',115,'প্রভু বোলে,—“আরে বেটা ! দধি দুগ্ধ আন’ ।
আজি তোর ঘরের লইমু মহাদান” ॥১১৫॥','прабху боле, — ‘а̄ре бет̣а̄! дадхи дугдха а̄на
а̄джи тора гхарера лаиму маха̄да̄на',NULL,NULL),('cb.adi.12.116','cb','cb.adi.12','ЧБ Ади 12.116',116,'গোপবৃন্দ দেখে যেন সাক্ষাৎ মদন ।
সম্ভ্রমে দিলেন আনি’ উত্তম আসন ॥১১৬॥
প্রভু-সঙ্গে গোপগণ করে পরিহাস ।
‘মামা মামা’ বলি’ সবে করয়ে সম্ভাষ ॥১১৭॥
কেহ বোলে,—“চল, মামা ভাত খাই গিয়া” ।
কোন গোপ কান্ধে করি’ যায় ঘরে লৈয়া ॥১১৮॥','гопа-вр̣нда декхе йена са̄кш̣а̄т мадана
самбхраме дилена а̄ни’ уттама а̄сана
прабху-сан̇ге гопа-ган̣а каре париха̄са
‘ма̄ма̄ ма̄ма̄’ бали’ сабе карайе самбха̄ш̣а
кеха боле, — ‘чала, ма̄ма̄, бха̄та кха̄и гийа̄’
кона гопа ка̄дхе кари йа̄йа гхаре лаийа̄',NULL,NULL),('cb.adi.12.119','cb','cb.adi.12','ЧБ Ади 12.119',119,'কেহ বোলে,—“যত ভাত ঘরের আমার ।
পূর্ব্বে যে খাইলা, মনে নাহিক তোমার ?” ॥১১৯॥','кеха боле, — ‘йата бха̄та гхарера а̄ма̄ра
пӯрве йе кха̄ила̄, мане на̄хика тома̄ра?’',NULL,NULL),('cb.adi.12.120','cb','cb.adi.12','ЧБ Ади 12.120',120,'সরস্বতী সত্য কহে, গোপ নাহি জানে ।
হাসে মহাপ্রভু গোপগণের বচনে ॥১২০॥','сарасватӣ сатйа кахе, гопа на̄хи джа̄не
ха̄се маха̄прабху гопа-ган̣ера вачане',NULL,NULL),('cb.adi.12.121','cb','cb.adi.12','ЧБ Ади 12.121',121,'দুগ্ধ, ঘৃত, দধি, সর, সুন্দর নবনী ।
সন্তোষে প্রভুরে সব গোপ দেয় আনি’ ॥১২১॥','дугдха, гхр̣та, дадхи, сара, сундара наванӣ
сантош̣е прабхуре саба гопа дейа а̄ни’',NULL,NULL),('cb.adi.12.122','cb','cb.adi.12','ЧБ Ади 12.122',122,'গোয়ালা-কুলেরে প্রভু প্রসন্ন হইয়া ।
গন্ধবণিকের ঘরে উঠিলেন গিয়া ॥১২২॥','гойа̄ла-кулере прабху прасанна хаийа̄
гандха-ван̣икера гхаре ут̣хилена гийа̄',NULL,NULL),('cb.adi.12.123','cb','cb.adi.12','ЧБ Ади 12.123',123,'সম্ভ্রমে বণিক্ করে চরণে প্রণাম ।
প্রভু বোলে,—“আরে ভাই, ভাল গন্ধ আন’” ॥১২৩॥','самбхраме ван̣ик каре чаран̣е пран̣а̄ма
